        for (let v = 1; v <= V_MAX; v++) {
            prefixSum[v] = (prefixSum[v - 1] + DP_prev[v]) % MOD;
        }

        // Calculate DP_curr[v]
        for (let v = 0; v <= V_MAX; v++) {
            if (sumDigits(v) === targetSi) {
                // DP_curr[v] = Sum(DP_prev[u] for u <= v)
                DP_curr[v] = prefixSum[v];
            }
            // If sumDigits(v) != targetSi, DP_curr[v] remains 0n
        }

        DP_prev = DP_curr;
    }

    // --- Step 3: Final Result ---
    let totalCount = 0n;
    for (let v = 0; v <= V_MAX; v++) {
        totalCount = (totalCount + DP_prev[v]) % MOD;
